package ru.memearena.security; import jakarta.servlet.http.HttpServletRequest; import org.springframework.beans.factory.annotation.Value; import org.springframework.stereotype.Component; import javax.crypto.Mac; import javax.crypto.spec.SecretKeySpec; import java.nio.charset.StandardCharsets;
@Component public class IpAddressService { private final boolean trust; private final String pepper; public IpAddressService(@Value("${app.proxy.trust-forwarded-headers:false}") boolean trust,@Value("${app.ip-hash-pepper:${APP_IP_HASH_PEPPER:local-dev-pepper-change-me}}") String pepper){this.trust=trust;this.pepper=pepper;} public String clientIp(HttpServletRequest r){ if(trust){String x=r.getHeader("X-Forwarded-For"); if(x!=null&&!x.isBlank()) return x.split(",")[0].trim();} return r.getRemoteAddr(); } public String hashIp(String ip){try{Mac mac=Mac.getInstance("HmacSHA256"); mac.init(new SecretKeySpec(pepper.getBytes(StandardCharsets.UTF_8),"HmacSHA256")); byte[] d=mac.doFinal((ip==null?"":ip).getBytes(StandardCharsets.UTF_8)); var sb=new StringBuilder(); for(byte b:d) sb.append(String.format("%02x",b)); return sb.toString();}catch(Exception e){throw new IllegalStateException(e);}} }
